import type { ParsedMessage } from '@/shared/types'
import { BaseAdapter } from './base'

const TURN_SEL    = 'article[data-turn]'
const MSG_SEL     = '[data-message-id]'
const ROLE_ATTR   = 'data-message-author-role'

export class ChatGPTAdapter extends BaseAdapter {
  readonly platform = 'chatgpt' as const

  detectPlatform(): boolean {
    return /^https:\/\/(chat\.openai\.com|chatgpt\.com)/.test(location.href)
  }

  extractConvId(url: string): string | null {
    const match = url.match(/\/c\/([0-9a-f-]{36})/)
    return match?.[1] ?? null
  }

  parseMessages(): ParsedMessage[] {
    const turns = document.querySelectorAll<HTMLElement>(TURN_SEL)
    console.log('[Aside:ChatGPT] Found turns:', turns.length)

    const results: ParsedMessage[] = []

    turns.forEach((turn) => {
      const turnRole = turn.getAttribute('data-turn') as ParsedMessage['role'] | null
      const msgEl = turn.querySelector<HTMLElement>(MSG_SEL)
      const platformId = msgEl?.getAttribute('data-message-id')
        ?? turn.getAttribute('data-turn-id')
        ?? `chatgpt-turn-${results.length}`

      const role: ParsedMessage['role'] =
        turnRole === 'user' || turnRole === 'assistant'
          ? turnRole
          : (msgEl?.getAttribute(ROLE_ATTR) as ParsedMessage['role']) ?? 'user'

      const content = this.extractContent(msgEl ?? turn, role)
      if (!content) return

      results.push({ platformId, role, content })
    })

    console.log('[Aside:ChatGPT] Parsed messages order:', results.map(m => m.role).join(', '))
    return results
  }

  private extractContent(el: HTMLElement | null, role: string): string {
    if (!el) return ''
    
    const prose = el.querySelector<HTMLElement>('.markdown, .prose, [class*="markdown"]')
    if (prose) {
      return this.htmlToMarkdown(prose)
    }
    
    return el.textContent?.trim() ?? ''
  }

  private htmlToMarkdown(el: HTMLElement): string {
    const clone = el.cloneNode(true) as HTMLElement

    const codeBlocks: string[] = []
    
    clone.querySelectorAll('pre').forEach(pre => {
      const cmContent = pre.querySelector('.cm-content')
      if (cmContent) {
        const code = cmContent.textContent || ''
        const placeholder = `__CODE_BLOCK_${codeBlocks.length}__`
        codeBlocks.push(`\n\`\`\`\n${code}\n\`\`\`\n`)
        pre.outerHTML = placeholder
        return
      }
      
      const code = pre.querySelector('code')
      if (code) {
        const langMatch = code.className.match(/language-(\w+)/)
        const lang = langMatch ? langMatch[1] : ''
        const content = code.textContent || ''
        const placeholder = `__CODE_BLOCK_${codeBlocks.length}__`
        codeBlocks.push(`\n\`\`\`${lang}\n${content}\n\`\`\`\n`)
        pre.outerHTML = placeholder
      }
    })

    clone.querySelectorAll('table').forEach(table => {
      const rows: string[] = []
      table.querySelectorAll('tr').forEach(tr => {
        const cells: string[] = []
        tr.querySelectorAll('th, td').forEach(cell => {
          cells.push(cell.textContent?.trim() || '')
        })
        rows.push('| ' + cells.join(' | ') + ' |')
      })
      if (rows.length > 0) {
        const colCount = rows[0].split('|').filter(c => c.trim()).length
        const separator = '| ' + Array(colCount).fill('---').join(' | ') + ' |'
        table.outerHTML = '\n\n' + rows[0] + '\n' + separator + '\n' + rows.slice(1).join('\n') + '\n\n'
      }
    })

    clone.querySelectorAll('code').forEach(code => {
      if (!code.closest('pre')) {
        code.outerHTML = `\`${code.textContent}\``
      }
    })

    clone.querySelectorAll('strong, b').forEach(b => {
      b.outerHTML = `**${b.textContent}**`
    })

    clone.querySelectorAll('em, i').forEach(i => {
      i.outerHTML = `*${i.textContent}*`
    })

    clone.querySelectorAll('h1').forEach(h => {
      h.outerHTML = `\n# ${h.textContent}\n`
    })
    clone.querySelectorAll('h2').forEach(h => {
      h.outerHTML = `\n## ${h.textContent}\n`
    })
    clone.querySelectorAll('h3').forEach(h => {
      h.outerHTML = `\n### ${h.textContent}\n`
    })

    clone.querySelectorAll('ul').forEach(ul => {
      ul.querySelectorAll(':scope > li').forEach(li => {
        const text = li.textContent?.trim() || ''
        li.outerHTML = `\n- ${text}`
      })
    })
    clone.querySelectorAll('ol').forEach(ol => {
      ol.querySelectorAll(':scope > li').forEach((li, idx) => {
        const text = li.textContent?.trim() || ''
        li.outerHTML = `\n${idx + 1}. ${text}`
      })
    })

    clone.querySelectorAll('hr').forEach(hr => {
      hr.outerHTML = '\n\n---\n\n'
    })

    clone.querySelectorAll('p').forEach(p => {
      p.outerHTML = `\n\n${p.textContent}\n\n`
    })

    clone.querySelectorAll('br').forEach(br => {
      br.outerHTML = '\n'
    })

    let result = clone.textContent?.trim() || ''
    
    codeBlocks.forEach((block, index) => {
      result = result.replace(`__CODE_BLOCK_${index}__`, block)
    })

    result = result.replace(/\n{3,}/g, '\n\n')

    return result
  }
}
