// 平台适配器基类 — 所有平台适配器继承此类
// ─────────────────────────────────────────────────────────

import type { PlatformAdapter, ParsedMessage, MessageRole } from '@/shared/types'

export abstract class BaseAdapter implements PlatformAdapter {
  abstract readonly platform: PlatformAdapter['platform']

  abstract detectPlatform(): boolean
  abstract parseMessages(): ParsedMessage[]
  abstract extractConvId(url: string): string | null

  /** Default: MutationObserver on document.body watching for new message nodes */
  observeChanges(callback: (msg: ParsedMessage) => void): () => void {
    let knownIds = new Set(this.parseMessages().map(m => m.platformId))

    const observer = new MutationObserver(() => {
      const current = this.parseMessages()
      for (const msg of current) {
        if (!knownIds.has(msg.platformId)) {
          knownIds.add(msg.platformId)
          callback(msg)
        }
      }
    })

    observer.observe(document.body, {
      childList: true,
      subtree: true,
    })

    return () => observer.disconnect()
  }

  protected cleanText(el: Element | null): string {
    return el?.textContent?.trim() ?? ''
  }

  protected guessRole(el: Element): MessageRole {
    const cls = el.className + ' ' + (el.getAttribute('data-author') ?? '')
    if (/user|human/i.test(cls)) return 'user'
    if (/assistant|ai|gpt|claude|model/i.test(cls)) return 'assistant'
    return 'user'
  }
}
