import { v4 as uuidv4 } from 'uuid'
import type { AsideFile, ConversationTree, Node, Message, PatchOp } from './types'

export const APP_VERSION = '0.1.0'
export const SCHEMA_VERSION = 'aside/v1' as const
export const FILE_VERSION = '1.0' as const

// ─── ID generation ──────────────────────────────────────

export const newId = (): string => uuidv4()

export const now = (): number => Date.now()

// ─── Empty constructors ──────────────────────────────────

export function createEmptyFile(): AsideFile {
  return {
    $schema: SCHEMA_VERSION,
    meta: {
      fileVersion: FILE_VERSION,
      createdAt: new Date().toISOString(),
      lastModified: new Date().toISOString(),
      appVersion: APP_VERSION,
    },
    trees: [],
    settings: {
      defaultView: 'tree',
      storageBackend: 'local-file',
    },
  }
}

export function createRootNode(treeId: string): Node {
  const id = newId()
  return {
    id,
    treeId,
    parentId: null,
    childrenIds: [],
    label: '根对话',
    messages: [],
    isStarred: false,
    isPruned: false,
    xRef: [],
    mergeFrom: [],
    position: { x: 0, y: 0 },
    annotations: [],
    createdAt: now(),
    updatedAt: now(),
  }
}

export function createChildNode(treeId: string, parentId: string, label = '新分支'): Node {
  return {
    id: newId(),
    treeId,
    parentId,
    childrenIds: [],
    label,
    messages: [],
    isStarred: false,
    isPruned: false,
    xRef: [],
    mergeFrom: [],
    position: { x: 0, y: 0 },
    annotations: [],
    createdAt: now(),
    updatedAt: now(),
  }
}

// ─── Tree lookup helpers ─────────────────────────────────

export function getNode(tree: ConversationTree, nodeId: string): Node | undefined {
  return tree.nodes.find(n => n.id === nodeId)
}

export function getChildren(tree: ConversationTree, nodeId: string): Node[] {
  const node = getNode(tree, nodeId)
  if (!node) return []
  return node.childrenIds.map(id => getNode(tree, id)).filter(Boolean) as Node[]
}

/** Returns all ancestor nodes from root down to (but not including) nodeId */
export function getAncestors(tree: ConversationTree, nodeId: string): Node[] {
  const path: Node[] = []
  let current = getNode(tree, nodeId)
  while (current?.parentId) {
    const parent = getNode(tree, current.parentId)
    if (!parent) break
    path.unshift(parent)
    current = parent
  }
  return path
}

/** Returns breadcrumb labels: ['根对话', '分支A', '当前节点'] */
export function getBreadcrumb(tree: ConversationTree, nodeId: string): string[] {
  const ancestors = getAncestors(tree, nodeId)
  const self = getNode(tree, nodeId)
  return [...ancestors.map(n => n.label), self?.label ?? ''].filter(Boolean)
}

// ─── Patch application (client-side) ────────────────────
// Applies a PatchOp to an AsideFile in-memory.
// The storage adapter will persist the result.

export function applyPatch(file: AsideFile, op: PatchOp): AsideFile {
  const trees = file.trees.map(tree => {
    if ('treeId' in op && op.treeId !== tree.id) return tree

    switch (op.op) {
      case 'addNode': {
        // Also update parent's childrenIds
        const nodes = tree.nodes.map(n =>
          n.id === op.node.parentId
            ? { ...n, childrenIds: [...n.childrenIds, op.node.id], updatedAt: now() }
            : n
        )
        return { ...tree, nodes: [...nodes, op.node], updatedAt: now() }
      }

      case 'updateNode':
        return {
          ...tree,
          nodes: tree.nodes.map(n =>
            n.id === op.nodeId ? { ...n, ...op.changes, updatedAt: now() } : n
          ),
          updatedAt: now(),
        }

      case 'pruneNode':
        return {
          ...tree,
          nodes: tree.nodes.map(n =>
            n.id === op.nodeId ? { ...n, isPruned: true, updatedAt: now() } : n
          ),
          updatedAt: now(),
        }

      case 'deleteNode': {
        // Collect all descendant ids to delete
        const toDelete = collectSubtreeIds(tree, op.nodeId)
        // Remove from parent's childrenIds
        const parentId = getNode(tree, op.nodeId)?.parentId
        return {
          ...tree,
          nodes: tree.nodes
            .filter(n => !toDelete.has(n.id))
            .map(n =>
              n.id === parentId
                ? { ...n, childrenIds: n.childrenIds.filter(id => id !== op.nodeId), updatedAt: now() }
                : n
            ),
          updatedAt: now(),
        }
      }

      case 'starNode':
        return {
          ...tree,
          nodes: tree.nodes.map(n =>
            n.id === op.nodeId ? { ...n, isStarred: op.value, updatedAt: now() } : n
          ),
          updatedAt: now(),
        }

      case 'addMessage':
        return {
          ...tree,
          nodes: tree.nodes.map(n =>
            n.id === op.nodeId
              ? { ...n, messages: [...n.messages, op.message], updatedAt: now() }
              : n
          ),
          updatedAt: now(),
        }

      case 'addAnnotation':
        return {
          ...tree,
          nodes: tree.nodes.map(n =>
            n.id === op.nodeId
              ? { ...n, annotations: [...n.annotations, op.annotation], updatedAt: now() }
              : n
          ),
          updatedAt: now(),
        }

      case 'updateTree':
        return { ...tree, ...op.changes, updatedAt: now() }

      default:
        return tree
    }
  })

  if (op.op === 'addTree') {
    return {
      ...file,
      trees: [...file.trees, op.tree],
      meta: { ...file.meta, lastModified: new Date().toISOString() },
    }
  }

  return {
    ...file,
    trees,
    meta: { ...file.meta, lastModified: new Date().toISOString() },
  }
}

function collectSubtreeIds(tree: ConversationTree, rootId: string): Set<string> {
  const ids = new Set<string>()
  const queue = [rootId]
  while (queue.length) {
    const id = queue.shift()!
    ids.add(id)
    const node = getNode(tree, id)
    node?.childrenIds.forEach(cid => queue.push(cid))
  }
  return ids
}

// ─── URL / platform utils ────────────────────────────────

export function extractOrigin(url: string): string {
  try { return new URL(url).origin } catch { return '' }
}

export function isSameConversation(urlA: string, urlB: string): boolean {
  // Compare up to query string, ignoring hash
  try {
    const a = new URL(urlA)
    const b = new URL(urlB)
    return a.origin === b.origin && a.pathname === b.pathname
  } catch { return false }
}

// ─── Debounce ────────────────────────────────────────────

export function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delayMs: number
): (...args: Parameters<T>) => void {
  let timer: ReturnType<typeof setTimeout>
  return (...args) => {
    clearTimeout(timer)
    timer = setTimeout(() => fn(...args), delayMs)
  }
}
